#include <vector>
#include <string>
#include <algorithm>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<pair<string, string>> validCoupons;

    // Define the order of business lines
    vector<string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Check each coupon
    for (int i = 0; i < code.size(); ++i) {
        // Check if code is valid
        bool isValidCode = !code[i].empty() && code[i].find_first_not_of("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_") == string::npos;

        // Check if business line is valid
        bool isValidBusiness = false;
        for (const string& b : businessOrder) {
            if (b == businessLine[i]) {
                isValidBusiness = true;
                break;
            }
        }

        // Check if active
        bool isActiveBool = isActive[i];

        // If all conditions are met, add to valid coupons
        if (isValidCode && isValidBusiness && isActiveBool) {
            validCoupons.push_back({code[i], businessLine[i]});
        }
    }

    // Sort by business line order and then by code lexicographically
    sort(validCoupons.begin(), validCoupons.end(), [](const pair<string, string>& a, const pair<string, string>& b) {
        int idxA = find(businessOrder.begin(), businessOrder.end(), a.second) - businessOrder.begin();
        int idxB = find(businessOrder.begin(), businessOrder.end(), b.second) - businessOrder.begin();
        if (idxA != idxB) return idxA < idxB;
        return a.first < b.first;
    });

    // Extract the codes in order
    vector<string> result;
    for (const auto& p : validCoupons) {
        result.push_back(p.first);
    }

    return result;
}

